import { NavLink, Outlet, useLocation, useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import logo from "../assets/logo.jpg";
import profile from "../assets/profile.jpg";
import { IoNotificationsOutline, IoMenu } from "react-icons/io5";
import { LuCircleUser } from "react-icons/lu";
import { RiLogoutCircleRLine } from "react-icons/ri";
import sidebarMap from "@/data/routes";

function MainPage() {
  const location = useLocation();
  const navigate = useNavigate();

  const getActiveMenu = () => {
    const path = location.pathname;
    if (path.startsWith("/dashboard/tenants")) return "Tenants";
    if (path.startsWith("/dashboard/rooms")) return "Rooms";
    if (path.startsWith("/dashboard/furniture")) return "Furniture";
    if (path.startsWith("/dashboard/lease")) return "Lease";
    if (path.startsWith("/dashboard/utility")) return "Utility bills & Payment";
    if (path.startsWith("/dashboard/report")) return "Report";
    if (path.startsWith("/dashboard/chat")) return "Chat";
    if (path.startsWith("/dashboard/recyclebin")) return "Recyclebin";
    return "Dashboard";
  };

  const activeMenu = getActiveMenu();
  const sidebarItems = sidebarMap[activeMenu] || {};

  const [menuOpen, setMenuOpen] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [lastSidebarPath, setLastSidebarPath] = useState({});

  useEffect(() => {
    const saved = localStorage.getItem("lastSidebarPath");
    if (saved) setLastSidebarPath(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem("lastSidebarPath", JSON.stringify(lastSidebarPath));
  }, [lastSidebarPath]);

  const handleTopMenuClick = (menuKey, defaultPath) => {
    navigate(lastSidebarPath[menuKey] || defaultPath);
    setMenuOpen(false);
  };

  return (
    <div className="min-h-screen bg-sky-50">
      {/* ============ NAVBAR ============ */}
      <header className="sticky top-0 z-50 bg-white border-b border-sky-100">
        <div className="flex items-center justify-between px-4 h-16">
          {/* LEFT */}
          <div className="flex items-center gap-3">
            <button
              className="md:hidden text-2xl text-sky-600"
              onClick={() => setSidebarOpen(!sidebarOpen)}
            >
              <IoMenu />
            </button>
            <img src={logo} className="w-9 h-9 rounded-full object-cover" />
            <span className="font-bold text-sky-700 hidden sm:block">
              Rental Admin
            </span>
          </div>

          {/* CENTER MENU (DESKTOP) */}
          <nav className="hidden lg:flex gap-6 text-sm font-medium">
            {[
              ["Dashboard", "/dashboard"],
              ["Tenants", "/dashboard/tenants"],
              ["Furniture", "/dashboard/furniture"],
              ["Rooms", "/dashboard/rooms"],
              ["Lease", "/dashboard/lease"],
              ["Utility bills & Payment", "/dashboard/utility"],
              ["Report", "/dashboard/report"],
              ["Recyclebin", "/dashboard/recyclebin"],
              ["Chat", "/dashboard/chat"],
            ].map(([label, path]) => (
              <button
                key={label}
                onClick={() => handleTopMenuClick(label, path)}
                className={`transition pb-1 ${
                  activeMenu === label
                    ? "text-sky-600 border-b-2 border-sky-600 font-semibold"
                    : "text-gray-500 hover:text-sky-600"
                }`}
              >
                {label === "Utility bills & Payment" ? "Utility" : label}
              </button>
            ))}
          </nav>

          {/* RIGHT */}
          <div className="flex items-center gap-4 relative">
            {/* MOBILE MENU */}
            <button
              className="lg:hidden text-2xl text-sky-600"
              onClick={() => setMenuOpen(!menuOpen)}
            >
              <IoMenu />
            </button>

            {/* NOTIFICATION */}
            <NavLink to="/dashboard/notifications" className="relative">
              <IoNotificationsOutline className="text-2xl text-sky-600" />
              <span className="absolute -top-1 -right-1 bg-sky-600 text-white text-xs px-1.5 rounded-full">
                3
              </span>
            </NavLink>

            {/* USER */}
            <div className="group relative">
              <img
                src={profile}
                className="w-9 h-9 rounded-full cursor-pointer border border-sky-200"
              />

              <div className="absolute right-0 mt-2 w-44 bg-white rounded-xl shadow-lg border border-sky-100 opacity-0 invisible group-hover:visible group-hover:opacity-100 transition">
                <button className="flex items-center gap-2 px-4 py-3 hover:bg-sky-50 w-full text-sm text-gray-700">
                  <LuCircleUser /> Profile
                </button>

                <button
                  onClick={() => {
                    localStorage.clear();
                    navigate("/login");
                  }}
                  className="flex items-center gap-2 px-4 py-3 hover:bg-red-50 text-red-500 w-full text-sm"
                >
                  <RiLogoutCircleRLine /> Logout
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* MOBILE TOP MENU */}
        {menuOpen && (
          <div className="lg:hidden bg-white border-t border-sky-100 px-4 py-3 grid gap-2 text-sm">
            {[
              ["Dashboard", "/dashboard"],
              ["Tenants", "/dashboard/tenants"],
              ["Furniture", "/dashboard/furniture"],
              ["Rooms", "/dashboard/rooms"],
              ["Lease", "/dashboard/lease"],
              ["Utility bills & Payment", "/dashboard/utility"],
              ["Report", "/dashboard/report"],
              ["Recyclebin", "/dashboard/recyclebin"],
              ["Chat", "/dashboard/chat"],
            ].map(([label, path]) => (
              <button
                key={label}
                onClick={() => handleTopMenuClick(label, path)}
                className="text-left py-2 text-gray-600 hover:text-sky-600"
              >
                {label === "Utility bills & Payment" ? "Utility" : label}
              </button>
            ))}
          </div>
        )}
      </header>

      {/* ============ MAIN ============ */}
      <div className="flex">
        {/* SIDEBAR */}
        <aside
          className={`bg-white w-64 border-r border-sky-100 min-h-[calc(100vh-64px)] fixed md:static z-40 transition-transform
          ${
            sidebarOpen ? "translate-x-0" : "-translate-x-full md:translate-x-0"
          }`}
        >
          <div className="p-4 space-y-1">
            {Object.entries(sidebarItems).map(([label, item]) => {
              const isIndex =
                item.path === `/dashboard/${activeMenu.toLowerCase()}` ||
                item.index === true;

              return (
                <NavLink
                  key={item.path}
                  to={item.path}
                  end={isIndex}
                  className={({ isActive }) =>
                    `block px-4 py-2 rounded-lg text-sm transition ${
                      isActive
                        ? "bg-sky-600 text-white shadow"
                        : "text-gray-600 hover:bg-sky-50 hover:text-sky-600"
                    }`
                  }
                  onClick={() =>
                    setLastSidebarPath((prev) => ({
                      ...prev,
                      [activeMenu]: item.path,
                    }))
                  }
                >
                  {label}
                </NavLink>
              );
            })}
          </div>
        </aside>

        {/* CONTENT */}
        <main className="flex-1 p-4 md:p-6">
          <Outlet />
        </main>
      </div>
    </div>
  );
}

export default MainPage;

import React, { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import toast, { Toaster } from "react-hot-toast";

export default function AddNewFurniture() {
  const navigate = useNavigate();
  const { id } = useParams();
  const isEdit = Boolean(id);

  const [photo, setPhoto] = useState(() => {
    if (!isEdit) return "";
    const data = JSON.parse(localStorage.getItem("furniture")) || [];
    const found = data.find((f) => f.id === Number(id));
    return found ? found.photo || "" : "";
  });
  const [name, setName] = useState(() => {
    if (!isEdit) return "";
    const data = JSON.parse(localStorage.getItem("furniture")) || [];
    const found = data.find((f) => f.id === Number(id));
    return found ? found.name || "" : "";
  });
  const [type, setType] = useState(() => {
    if (!isEdit) return "";
    const data = JSON.parse(localStorage.getItem("furniture")) || [];
    const found = data.find((f) => f.id === Number(id));
    return found ? found.type || "" : "";
  });
  const [condition, setCondition] = useState(() => {
    if (!isEdit) return "Good";
    const data = JSON.parse(localStorage.getItem("furniture")) || [];
    const found = data.find((f) => f.id === Number(id));
    return found ? found.condition || found.status || "Good" : "Good";
  });



  // ===== IMAGE UPLOAD =====
  const handlePhotoChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => setPhoto(reader.result);
    reader.readAsDataURL(file);
  };

  // ===== SAVE =====
  const handleSave = (e) => {
    e.preventDefault();

    if (!name || !type) {
      toast.error("Please fill all required fields");
      return;
    }

    const data = JSON.parse(localStorage.getItem("furniture")) || [];

    if (isEdit) {
      const updated = data.map((f) =>
        f.id === Number(id) ? { ...f, photo, name, type, condition } : f
      );
      localStorage.setItem("furniture", JSON.stringify(updated));
      toast.success("Furniture updated successfully");
    } else {
      const newItem = {
        id: Date.now(),
        photo,
        name,
        type,
        condition,
        createdAt: new Date(),
      };
      localStorage.setItem("furniture", JSON.stringify([...data, newItem]));
      toast.success("Furniture added successfully");
    }

    setTimeout(() => navigate("/dashboard/furniture"), 500);
  };

  return (
    <div className="p-6 min-h-screen bg-sky-50">
      <Toaster position="top-right" />

      <div className="bg-white rounded-2xl shadow-lg p-8 max-w-3xl mx-auto">
        <h2 className="text-2xl font-bold text-sky-900 mb-1 text-center">
          {isEdit ? "Edit Furniture" : "Add New Furniture"}
        </h2>
        <p className="text-center text-slate-500 mb-8">
          Enter furniture details below
        </p>

        <form onSubmit={handleSave} className="grid grid-cols-1 gap-6">
          {/* IMAGE */}
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-2">
              Furniture Photo
            </label>

            <label className="relative block w-full max-w-md cursor-pointer group">
              <img
                src={
                  photo ||
                  "https://mocra.org/wp-content/uploads/2016/07/default.jpg"
                }
                alt="furniture"
                className="w-full h-48 object-cover rounded-2xl border border-slate-200 shadow-sm"
              />

              <div className="absolute inset-0 bg-black/40 rounded-2xl flex items-center justify-center opacity-0 group-hover:opacity-100 transition">
                <span className="text-white text-sm font-medium">
                  Change Photo
                </span>
              </div>

              <input
                type="file"
                accept="image/*"
                onChange={handlePhotoChange}
                className="hidden"
              />
            </label>
          </div>

          {/* NAME */}
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">
              Furniture Name *
            </label>
            <input
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="e.g. Bed, Table, Chair"
              className="w-full px-4 py-2.5 rounded-lg border border-slate-300
              focus:ring-2 focus:ring-sky-400 focus:border-sky-400 outline-none"
              required
            />
          </div>

          {/* TYPE */}
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">
              Furniture Type *
            </label>
            <select
              value={type}
              onChange={(e) => setType(e.target.value)}
              className="w-full px-4 py-2.5 rounded-lg border border-slate-300
              focus:ring-2 focus:ring-sky-400 focus:border-sky-400 outline-none"
              required
            >
              <option value="">Select type</option>
              <option value="Wood">Wood</option>
              <option value="Metal">Metal</option>
              <option value="Plastic">Plastic</option>
              <option value="Mixed">Mixed</option>
            </select>
          </div>

          {/* CONDITION */}
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">
              Condition
            </label>
            <select
              value={condition}
              onChange={(e) => setCondition(e.target.value)}
              className="w-full px-4 py-2.5 rounded-lg border border-slate-300
              focus:ring-2 focus:ring-sky-400 focus:border-sky-400 outline-none"
            >
              <option value="New">New</option>
              <option value="Good">Good</option>
              <option value="Fair">Fair</option>
              <option value="Broken">Broken</option>
            </select>
          </div>

          {/* ACTIONS */}
          <div className="flex justify-end gap-4 pt-4">
            <button
              type="button"
              onClick={() => navigate("/dashboard/furniture")}
              className="px-5 py-2 rounded-lg border hover:bg-gray-100"
            >
              Cancel
            </button>

            <button
              type="submit"
              className="px-6 py-2 rounded-lg bg-sky-600 text-white hover:bg-sky-700 shadow"
            >
              {isEdit ? "Update Furniture" : "Save Furniture"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

