import React, { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import toast, { Toaster } from "react-hot-toast";

export default function CreateNewLease() {
  const navigate = useNavigate();
  const { id } = useParams();
  const isEdit = Boolean(id);

  const [tenant, setTenant] = useState(() => {
    if (!isEdit) return "";
    const leases = JSON.parse(localStorage.getItem("leases")) || [];
    const found = leases.find((l) => l.id === Number(id));
    return found ? found.tenant : "";
  });
  const [room, setRoom] = useState(() => {
    if (!isEdit) return "";
    const leases = JSON.parse(localStorage.getItem("leases")) || [];
    const found = leases.find((l) => l.id === Number(id));
    return found ? found.room : "";
  });
  const [rent, setRent] = useState(() => {
    if (!isEdit) return "";
    const leases = JSON.parse(localStorage.getItem("leases")) || [];
    const found = leases.find((l) => l.id === Number(id));
    return found ? found.rent : "";
  });
  const [startDate, setStartDate] = useState(() => {
    if (!isEdit) return "";
    const leases = JSON.parse(localStorage.getItem("leases")) || [];
    const found = leases.find((l) => l.id === Number(id));
    return found ? found.startDate : "";
  });
  const [endDate, setEndDate] = useState(() => {
    if (!isEdit) return "";
    const leases = JSON.parse(localStorage.getItem("leases")) || [];
    const found = leases.find((l) => l.id === Number(id));
    return found ? found.endDate : "";
  });
  const [status, setStatus] = useState(() => {
    if (!isEdit) return "Inactive";
    const leases = JSON.parse(localStorage.getItem("leases")) || [];
    const found = leases.find((l) => l.id === Number(id));
    return found ? found.status || "Inactive" : "Inactive";
  });

  const [rooms, setRooms] = useState(() => {
    return JSON.parse(localStorage.getItem("rooms")) || [];
  });



  // ===== AUTO STATUS BY DATE =====
  useEffect(() => {
    if (!startDate || !endDate) return;

    const today = new Date().toISOString().split("T")[0];
    if (today >= startDate && today <= endDate) {
      setStatus("Active");
    } else {
      setStatus("Inactive");
    }
  }, [startDate, endDate]);

  // ===== SAVE =====
  const handleSubmit = (e) => {
    e.preventDefault();

    if (!tenant || !room || !rent || !startDate || !endDate) {
      toast.error("Please fill all fields");
      return;
    }

    const leases = JSON.parse(localStorage.getItem("leases")) || [];

    if (isEdit) {
      const updated = leases.map((l) =>
        l.id === Number(id)
          ? { ...l, tenant, room, rent, startDate, endDate, status }
          : l
      );
      localStorage.setItem("leases", JSON.stringify(updated));
      toast.success("Lease updated");
    } else {
      const newLease = {
        id: Date.now(),
        tenant,
        room,
        rent,
        startDate,
        endDate,
        status,
      };
      localStorage.setItem("lease", JSON.stringify([...leases, newLease]));
      toast.success("Lease added");
    }

    navigate("/dashboard/lease");
  };

  return (
    <div className="min-h-screen bg-sky-50 p-6">
      <Toaster position="top-right" />

      <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl shadow">
        <h2 className="text-2xl font-bold mb-6 text-sky-900 text-center">
          {isEdit ? "Edit Lease" : "Add Lease"}
        </h2>

        <form onSubmit={handleSubmit} className="space-y-5">
          {/* TENANT */}
          <div>
            <label className="block text-sm font-medium mb-1">
              Tenant Name
            </label>
            <input
              value={tenant}
              onChange={(e) => setTenant(e.target.value)}
              className="w-full border rounded-lg px-4 py-2"
              placeholder="Enter tenant name"
            />
          </div>

          {/* ROOM */}
          <div>
            <label className="block text-sm font-medium mb-1">Room</label>
            <select
              value={room}
              onChange={(e) => setRoom(e.target.value)}
              className="w-full border rounded-lg px-4 py-2"
            >
              <option value="">-- Select Room --</option>
              {rooms.map((r) => (
                <option key={r.id} value={r.name}>
                  {r.name}
                </option>
              ))}
            </select>
          </div>

          {/* RENT */}
          <div>
            <label className="block text-sm font-medium mb-1">
              Monthly Rent
            </label>
            <input
              type="number"
              value={rent}
              onChange={(e) => setRent(e.target.value)}
              className="w-full border rounded-lg px-4 py-2"
            />
          </div>

          {/* DATES */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">
                Start Date
              </label>
              <input
                type="date"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="w-full border rounded-lg px-4 py-2"
              />
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">End Date</label>
              <input
                type="date"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="w-full border rounded-lg px-4 py-2"
              />
            </div>
          </div>

          {/* STATUS */}
          <div>
            <label className="block text-sm font-medium mb-1">Status</label>
            <input
              value={status}
              disabled
              className="w-full bg-gray-100 border rounded-lg px-4 py-2 text-gray-600"
            />
          </div>

          {/* BUTTONS */}
          <div className="flex justify-end gap-3 pt-4">
            <button
              type="button"
              onClick={() => navigate(-1)}
              className="border px-5 py-2 rounded-lg"
            >
              Cancel
            </button>
            <button
              type="submit"
              className="bg-sky-600 text-white px-6 py-2 rounded-lg hover:bg-sky-700"
            >
              {isEdit ? "Update Lease" : "Save Lease"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { FiEdit2, FiTrash2, FiSearch, FiEye, FiPlus } from "react-icons/fi";

export default function Leases() {
  const navigate = useNavigate();

  const [search, setSearch] = useState("");
  const [leases, setLeases] = useState(() => {
    const saved = JSON.parse(localStorage.getItem("leases")) || [];
    return saved.map((l) => ({
      ...l,
      status: l.status || "Active",
    }));
  });

  const [showModal, setShowModal] = useState(false);
  const [selectedItem, setSelectedItem] = useState(null);

  const [currentPage, setCurrentPage] = useState(1);
  const [rowsPerPage, setRowsPerPage] = useState(5);

  const [selectedIds, setSelectedIds] = useState([]);
  const [showBulkDelete, setShowBulkDelete] = useState(false);

  const [sortField, setSortField] = useState("tenant"); // tenant | status
  const [sortOrder, setSortOrder] = useState("asc"); // asc | desc



  // ===== FILTER + SORT =====
  const filtered = [...leases]
    .filter(
      (l) =>
        l.tenant?.toLowerCase().includes(search.trim().toLowerCase()) ||
        l.room?.toLowerCase().includes(search.trim().toLowerCase())
    )
    .sort((a, b) => {
      let valA = a[sortField] || "";
      let valB = b[sortField] || "";

      if (typeof valA === "string") valA = valA.toLowerCase();
      if (typeof valB === "string") valB = valB.toLowerCase();

      if (valA < valB) return sortOrder === "asc" ? -1 : 1;
      if (valA > valB) return sortOrder === "asc" ? 1 : -1;
      return 0;
    });

  // ===== PAGINATION =====
  const lastIndex = currentPage * rowsPerPage;
  const firstIndex = lastIndex - rowsPerPage;
  const paginated = filtered.slice(firstIndex, lastIndex);
  const totalPages = Math.ceil(filtered.length / rowsPerPage);

  // ===== SELECT ALL =====
  const allChecked =
    paginated.length > 0 && paginated.every((l) => selectedIds.includes(l.id));

  const toggleSelectAll = (checked) => {
    if (checked) {
      const newIds = paginated
        .map((l) => l.id)
        .filter((id) => !selectedIds.includes(id));
      setSelectedIds([...selectedIds, ...newIds]);
    } else {
      setSelectedIds(
        selectedIds.filter((id) => !paginated.some((l) => l.id === id))
      );
    }
  };

  // ===== SINGLE DELETE =====
  const confirmDelete = () => {
    const updated = leases.filter((l) => l.id !== selectedItem.id);
    setLeases(updated);
    localStorage.setItem("leases", JSON.stringify(updated));
    toast.success("Lease deleted successfully");
    setShowModal(false);
    setSelectedItem(null);
  };

  return (
    <div className="p-6 bg-sky-50 min-h-screen space-y-6">
      <Toaster position="top-right" />

      {/* ===== HEADER ===== */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <h2 className="text-2xl font-bold text-sky-900">All Leases</h2>
        <button
          onClick={() => navigate("/dashboard/lease/createnewlease")}
          className="bg-sky-600 hover:bg-sky-700 text-white px-5 py-2 rounded-lg shadow transition"
        >
          + Add New Lease
        </button>
      </div>

      {/* ===== SEARCH ===== */}
      <div className="bg-white p-4 rounded-xl shadow">
        <input
          type="text"
          placeholder="Search by tenant or room..."
          value={search}
          onChange={(e) => {
            setSearch(e.target.value);
            setCurrentPage(1);
          }}
          className="w-full border border-sky-200 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-sky-400"
        />
      </div>

      {/* ===== TABLE ===== */}
      <div className="bg-white rounded-xl shadow overflow-x-auto">
        <table className="min-w-full text-sm border-separate border-spacing-y-2">
          <thead className="bg-sky-100 text-sky-900">
            <tr>
              {/* SELECT ALL */}
              <th className="px-5 py-4 text-left w-[60px]">
                <input
                  type="checkbox"
                  checked={allChecked}
                  onChange={(e) => toggleSelectAll(e.target.checked)}
                  className="w-4 h-4 accent-sky-600"
                />
              </th>

              {/* TENANT SORT */}
              <th className="px-5 py-4 text-left w-[25%]">
                <button
                  onClick={() => {
                    setSortField("tenant");
                    setSortOrder(
                      sortField === "tenant" && sortOrder === "asc"
                        ? "desc"
                        : "asc"
                    );
                  }}
                  className="hover:text-sky-700"
                >
                  Tenant
                </button>
              </th>

              <th className="px-5 py-4 text-left w-[20%]">Room</th>

              <th className="px-5 py-4 text-left w-[20%]">Duration</th>

              <th className="px-5 py-4 text-left w-[15%]">Rent</th>

              {/* STATUS SORT */}
              <th className="px-5 py-4 text-left w-[10%]">
                <button
                  onClick={() => {
                    setSortField("status");
                    setSortOrder(
                      sortField === "status" && sortOrder === "asc"
                        ? "desc"
                        : "asc"
                    );
                  }}
                  className="hover:text-sky-700"
                >
                  Status
                </button>
              </th>

              <th className="px-5 py-4 text-center w-[15%]">Action</th>
            </tr>
          </thead>

          <tbody>
            {paginated.map((l) => (
              <tr
                key={l.id}
                className="bg-white hover:bg-sky-50 transition shadow-sm rounded-lg"
              >
                {/* CHECKBOX */}
                <td className="px-5 py-4 rounded-l-lg">
                  <input
                    type="checkbox"
                    checked={selectedIds.includes(l.id)}
                    onChange={(e) => {
                      if (e.target.checked) {
                        setSelectedIds([...selectedIds, l.id]);
                      } else {
                        setSelectedIds(selectedIds.filter((id) => id !== l.id));
                      }
                    }}
                    className="w-4 h-4 accent-sky-600"
                  />
                </td>

                {/* TENANT */}
                <td className="px-5 py-4 font-semibold text-slate-800">
                  {l.tenant}
                </td>

                {/* ROOM */}
                <td className="px-5 py-4">{l.room}</td>

                {/* DURATION */}
                <td className="px-5 py-4 text-xs text-slate-600">
                  {l.startDate} ΓåÆ {l.endDate}
                </td>

                {/* RENT */}
                <td className="px-5 py-4 font-medium text-slate-800">
                  ${l.rent}
                </td>

                {/* STATUS */}
                <td className="px-5 py-4">
                  <span
                    className={`px-3 py-1 text-xs font-semibold rounded-full
                      ${
                        l.status === "Active"
                          ? "bg-green-100 text-green-700"
                          : "bg-gray-200 text-gray-700"
                      }`}
                  >
                    {l.status}
                  </span>
                </td>

                {/* ACTION */}
                <td className="px-5 py-4 rounded-r-lg">
                  <div className="flex justify-center gap-3">
                    <button
                      onClick={() => navigate(`/dashboard/lease/view/${l.id}`)}
                      className="px-3 py-1 text-xs rounded-md text-green-700 hover:bg-green-100"
                    >
                      View
                    </button>

                    <button
                      onClick={() => navigate(`/dashboard/lease/edit/${l.id}`)}
                      className="px-3 py-1 text-xs rounded-md text-indigo-700 hover:bg-indigo-100"
                    >
                      Edit
                    </button>

                    <button
                      onClick={() => {
                        setSelectedItem(l);
                        setShowModal(true);
                      }}
                      className="px-3 py-1 text-xs rounded-md text-red-700 hover:bg-red-100"
                    >
                      Delete
                    </button>
                  </div>
                </td>
              </tr>
            ))}

            {filtered.length === 0 && (
              <tr>
                <td colSpan="7" className="text-center py-12 text-gray-400">
                  No leases found
                </td>
              </tr>
            )}
          </tbody>
        </table>

        {/* BULK DELETE */}
        {selectedIds.length > 0 && (
          <div className="p-4">
            <button
              onClick={() => setShowBulkDelete(true)}
              className="bg-red-600 text-white px-5 py-2 rounded-lg hover:bg-red-700"
            >
              Delete Selected ({selectedIds.length})
            </button>
          </div>
        )}
      </div>

      {/* ===== PAGINATION ===== */}
      <div className="flex flex-col sm:flex-row justify-between items-center gap-4 mt-4">
        <div className="flex items-center gap-2 text-sm">
          Show
          <select
            value={rowsPerPage}
            onChange={(e) => {
              setRowsPerPage(Number(e.target.value));
              setCurrentPage(1);
            }}
            className="border rounded px-2 py-1"
          >
            <option value={5}>5</option>
            <option value={10}>10</option>
          </select>
          entries
        </div>

        <div className="flex items-center gap-2">
          <button
            disabled={currentPage === 1}
            onClick={() => setCurrentPage((p) => p - 1)}
            className="px-3 py-1 rounded border disabled:opacity-40"
          >
            Prev
          </button>

          {[...Array(totalPages)].map((_, i) => (
            <button
              key={i}
              onClick={() => setCurrentPage(i + 1)}
              className={`px-3 py-1 rounded border ${
                currentPage === i + 1 ? "bg-sky-600 text-white" : ""
              }`}
            >
              {i + 1}
            </button>
          ))}

          <button
            disabled={currentPage === totalPages}
            onClick={() => setCurrentPage((p) => p + 1)}
            className="px-3 py-1 rounded border disabled:opacity-40"
          >
            Next
          </button>
        </div>
      </div>

      {/* ===== DELETE MODAL ===== */}
      <AnimatePresence>
        {showModal && selectedItem && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 px-4"
          >
            <motion.div
              initial={{ scale: 0.85, y: 30, opacity: 0 }}
              animate={{ scale: 1, y: 0, opacity: 1 }}
              exit={{ scale: 0.85, y: 30, opacity: 0 }}
              className="bg-white rounded-2xl shadow-xl w-full max-w-md p-8 text-center"
            >
              <h3 className="text-xl font-bold mb-3">Delete Lease</h3>
              <p className="mb-4">
                Delete lease for <b>{selectedItem.tenant}</b>?
              </p>

              <div className="flex justify-center gap-4">
                <button
                  onClick={() => setShowModal(false)}
                  className="px-5 py-2 rounded-lg border"
                >
                  Cancel
                </button>

                <button
                  onClick={confirmDelete}
                  className="px-5 py-2 rounded-lg bg-red-600 text-white"
                >
                  Yes, Delete
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* ===== BULK DELETE MODAL ===== */}
      {showBulkDelete && (
        <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl p-6 w-full max-w-md shadow-lg">
            <h3 className="text-lg font-bold mb-2">Confirm Delete</h3>
            <p className="mb-5">
              Delete <b>{selectedIds.length}</b> selected leases?
            </p>

            <div className="flex justify-end gap-3">
              <button
                onClick={() => setShowBulkDelete(false)}
                className="px-4 py-2 rounded-lg border"
              >
                Cancel
              </button>

              <button
                onClick={() => {
                  const updated = leases.filter(
                    (l) => !selectedIds.includes(l.id)
                  );
                  setLeases(updated);
                  localStorage.setItem("leases", JSON.stringify(updated));
                  setSelectedIds([]);
                  setShowBulkDelete(false);
                  toast.success("Selected leases deleted");
                }}
                className="px-4 py-2 rounded-lg bg-red-600 text-white"
              >
                Yes, Delete
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

