import React, { useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import toast, { Toaster } from "react-hot-toast";

export default function EditRoom() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [room, setRoom] = useState(() => {
    const rooms = JSON.parse(localStorage.getItem("rooms")) || [];
    return rooms.find((r) => r.id === Number(id)) || null;
  });
  const [allFurniture, setAllFurniture] = useState(() => {
    return JSON.parse(localStorage.getItem("furniture")) || [];
  });
  const [selectedFurniture, setSelectedFurniture] = useState(() => {
    const rooms = JSON.parse(localStorage.getItem("rooms")) || [];
    const found = rooms.find((r) => r.id === Number(id));
    return found ? found.furniture || [] : [];
  });
  const [photo, setPhoto] = useState(() => {
    const rooms = JSON.parse(localStorage.getItem("rooms")) || [];
    const found = rooms.find((r) => r.id === Number(id));
    return found ? found.photo || "" : "";
  });

  const handlePhotoChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => setPhoto(reader.result);
    reader.readAsDataURL(file);
  };

  const handleUpdate = (e) => {
    e.preventDefault();

    const rooms = JSON.parse(localStorage.getItem("rooms")) || [];
    const updated = rooms.map((r) =>
      r.id === Number(id) ? { ...room, photo, furniture: selectedFurniture } : r
    );

    localStorage.setItem("rooms", JSON.stringify(updated));
    toast.success("Room updated successfully");
    navigate("/dashboard/rooms");
  };

  if (!room) return null;

  return (
    <div className="min-h-screen bg-gradient-to-br from-sky-50 to-white p-6">
      <Toaster />
      <div className="max-w-4xl mx-auto bg-white rounded-2xl shadow-xl p-8">
        <h2 className="text-2xl font-bold text-sky-900 mb-6">Edit Room</h2>

        <form onSubmit={handleUpdate} className="space-y-8">
          {/* ROOM IMAGE UPLOAD */}
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-2">
              Room Photo
            </label>

            <label className="relative block w-full max-w-md cursor-pointer group">
              {/* IMAGE PREVIEW */}
              <img
                src={
                  photo ||
                  "https://via.placeholder.com/600x350?text=Upload+Room+Photo"
                }
                alt="room"
                className="w-full h-56 object-cover rounded-2xl border border-slate-200 shadow-sm"
              />

              {/* HOVER OVERLAY */}
              <div className="absolute inset-0 bg-black/40 rounded-2xl flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition">
                <svg
                  xmlns="http://www.w3.org/2000/svg"
                  className="w-10 h-10 text-white mb-2"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M3 7h4l2-3h6l2 3h4v11H3V7z"
                  />
                  <circle cx="12" cy="13" r="3" />
                </svg>
                <span className="text-white text-sm font-medium">
                  Change Photo
                </span>
              </div>

              {/* FILE INPUT */}
              <input
                type="file"
                accept="image/*"
                onChange={handlePhotoChange}
                className="hidden"
              />
            </label>

            <p className="text-xs text-slate-400 mt-2">
              Click the image to upload or change room photo
            </p>
          </div>

          {/* INFO */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm text-slate-600 mb-1">
                Room Name
              </label>
              <input
                value={room.name}
                onChange={(e) => setRoom({ ...room, name: e.target.value })}
                className="w-full px-4 py-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-sky-400 outline-none"
              />
            </div>

            <div>
              <label className="block text-sm text-slate-600 mb-1">
                Base Rent ($)
              </label>
              <input
                type="number"
                value={room.rent}
                onChange={(e) => setRoom({ ...room, rent: e.target.value })}
                className="w-full px-4 py-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-sky-400 outline-none"
              />
            </div>

            <div>
              <label className="block text-sm text-slate-600 mb-1">
                Status
              </label>
              <select
                value={room.status}
                onChange={(e) => setRoom({ ...room, status: e.target.value })}
                className="w-full px-4 py-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-sky-400 outline-none"
              >
                <option value="Free">Free</option>
                <option value="Occupied">Occupied</option>
              </select>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm text-slate-600 mb-1">
                Description
              </label>
              <textarea
                rows={3}
                value={room.description}
                onChange={(e) =>
                  setRoom({ ...room, description: e.target.value })
                }
                className="w-full px-4 py-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-sky-400 outline-none resize-none"
              />
            </div>
          </div>

          {/* FURNITURE */}
          <div className="bg-sky-50 border border-sky-100 rounded-2xl p-6">
            <h3 className="text-lg font-semibold text-sky-900 mb-1">
              Assign Furniture
            </h3>
            <div className="grid sm:grid-cols-2 md:grid-cols-3 gap-3 mt-4">
              {allFurniture.map((f) => {
                const checked = selectedFurniture.includes(f.id);
                return (
                  <label
                    key={f.id}
                    className={`flex gap-3 p-3 rounded-xl border cursor-pointer
                    ${
                      checked
                        ? "bg-white border-sky-400"
                        : "bg-white/70 border-slate-200"
                    }`}
                  >
                    <input
                      type="checkbox"
                      checked={checked}
                      onChange={(e) => {
                        if (e.target.checked)
                          setSelectedFurniture([...selectedFurniture, f.id]);
                        else
                          setSelectedFurniture(
                            selectedFurniture.filter((id) => id !== f.id)
                          );
                      }}
                      className="accent-sky-600 mt-1"
                    />
                    <div>
                      <p className="font-medium">{f.name}</p>
                      <p className="text-xs text-gray-400">{f.type}</p>
                    </div>
                  </label>
                );
              })}
            </div>
          </div>

          {/* BUTTONS */}
          <div className="flex justify-end gap-4 pt-4 border-t">
            <button
              type="button"
              onClick={() => navigate("/dashboard/rooms")}
              className="px-5 py-2.5 rounded-lg border hover:bg-slate-100"
            >
              Cancel
            </button>
            <button
              type="submit"
              className="px-6 py-2.5 rounded-lg bg-sky-600 text-white hover:bg-sky-700"
            >
              Update Room
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import React, { useState } from "react";
import { useNavigate, useParams } from "react-router-dom";

export default function ViewRoom() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [room, setRoom] = useState(() => {
    const rooms = JSON.parse(localStorage.getItem("rooms")) || [];
    return rooms.find((r) => r.id === Number(id)) || null;
  });
  const [furnitureList, setFurnitureList] = useState(() => {
    const furniture = JSON.parse(localStorage.getItem("furniture")) || [];
    return furniture.map((f) => ({
      ...f,
      condition: f.condition || f.status || "Good",
    }));
  });

  if (!room) return null;

  const assignedFurniture = furnitureList.filter((f) =>
    (room.furniture || []).includes(f.id)
  );

  return (
    <div className="min-h-screen bg-sky-50 p-6">
      <div className="max-w-5xl mx-auto bg-white rounded-2xl shadow-xl overflow-hidden">
        {/* IMAGE */}
        <img
          src={room.photo || "https://via.placeholder.com/800x300"}
          alt={room.name}
          className="w-full h-64 object-cover"
        />

        <div className="p-8 space-y-6">
          {/* HEADER */}
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-bold text-sky-900">{room.name}</h2>
              <p className="text-sm text-slate-500">
                ${room.rent} / month ΓÇó{" "}
                <span
                  className={`font-medium ${
                    room.status === "Free" ? "text-green-600" : "text-red-600"
                  }`}
                >
                  {room.status}
                </span>
              </p>
            </div>

            <button
              onClick={() => navigate(`/dashboard/rooms/edit/${room.id}`)}
              className="px-5 py-2 rounded-lg bg-sky-600 text-white hover:bg-sky-700"
            >
              Edit Room
            </button>
          </div>

          {/* DESCRIPTION */}
          <div>
            <h4 className="font-semibold mb-1">Description</h4>
            <p className="text-gray-600">
              {room.description || "No description provided"}
            </p>
          </div>

          {/* FURNITURE */}
          <div>
            <h4 className="font-semibold mb-3">Furniture in this Room</h4>

            {assignedFurniture.length === 0 ? (
              <p className="text-sm text-gray-400">No furniture assigned</p>
            ) : (
              <div className="grid sm:grid-cols-2 md:grid-cols-3 gap-4">
                {assignedFurniture.map((f) => (
                  <div key={f.id} className="border rounded-xl p-4 bg-sky-50">
                    <p className="font-medium">{f.name}</p>
                    <p className="text-xs text-gray-500">{f.type}</p>
                    <span
                      className={`inline-block mt-1 px-3 py-1 text-xs font-semibold rounded-full
                        ${
                          f.condition === "New"
                            ? "bg-blue-100 text-blue-700"
                            : f.condition === "Good"
                            ? "bg-green-100 text-green-700"
                            : f.condition === "Broken"
                            ? "bg-red-100 text-red-700"
                            : "bg-yellow-100 text-yellow-700"
                        }`}
                    >
                      {f.condition}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="bg-white rounded-2xl shadow p-6 space-y-4">
            <div className="flex items-center justify-between">
              <div className="px-4 py-2 rounded-lg bg-green-600 text-white cursor-pointer opacity-50">
                {/* Removing broken nav state block due to undefined tenant */}
                + Create New Lease
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="bg-sky-100">
                  <tr>
                    <th className="px-4 py-3 text-left">Room</th>
                    <th className="px-4 py-3 text-left">Dates</th>
                    <th className="px-4 py-3 text-left">Rent</th>
                    <th className="px-4 py-3 text-left">Status</th>
                  </tr>
                </thead>
                <tbody>
                  <tr>
                    <td colSpan="4" className="text-center py-10 text-gray-400">
                      No lease history for this tenant.
                    </td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>

          {/* BACK */}
          <div className="pt-4 border-t">
            <button
              onClick={() => navigate("/dashboard/rooms")}
              className="px-5 py-2 rounded-lg border hover:bg-slate-100"
            >
              Back to Rooms
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState } from "react";
import { useParams, useNavigate, Link } from "react-router-dom";
// import "./createAccount.css";
import { FaEye, FaEyeSlash } from "react-icons/fa";

function CreateAccount() {
  const { id } = useParams(); // tenant id from URL
  const navigate = useNavigate();

  const [tenant, setTenant] = useState(() => {
    const tenants = JSON.parse(localStorage.getItem("tenants")) || [];
    return tenants.find((t) => t.id.toString() === id); // convert to string
  });
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [error, setError] = useState(() => {
    const tenants = JSON.parse(localStorage.getItem("tenants")) || [];
    const found = tenants.find((t) => t.id.toString() === id);
    return found ? "" : "Tenant not found";
  });
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const isPasswordMismatch = confirmPassword && password !== confirmPassword;

  const handleSubmit = (e) => {
    e.preventDefault();
    if (password !== confirmPassword) {
      setError("Passwords do not match");
      return;
    }

    const tenants = JSON.parse(localStorage.getItem("tenants")) || [];
    const updatedTenants = tenants.map((t) =>
      t.id.toString() === id
        ? { ...t, status: "Linked", account: { password } }
        : t,
    );
    localStorage.setItem("tenants", JSON.stringify(updatedTenants));

    // alert("Account created successfully!");
    navigate("/dashboard/tenants");
  };

  if (!tenant) return <p>{error || "Loading tenant..."}</p>;

  return (
    <div className="min-h-screen to-white flex items-center justify-center px-4">
      <div className="w-full max-w-md bg-white rounded-2xl shadow-xl p-8">
        {/* ===== TITLE ===== */}
        <h1 className="text-2xl font-bold text-center text-slate-800 mb-1">
          Create Account for{" "}
          <span className="text-sky-600 font-semibold">{tenant.name}</span>
        </h1>

        {/* ===== FORM ===== */}
        <form onSubmit={handleSubmit} className="space-y-5">
          {/* Tenant Name */}
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">
              Tenant Name
            </label>
            <input
              type="text"
              value={tenant.name}
              disabled
              className="w-full px-4 py-2.5 rounded-lg border border-slate-300 bg-slate-100 text-slate-600 cursor-not-allowed"
            />
          </div>

          {/* Email */}
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">
              Email
            </label>
            <input
              type="email"
              value={tenant.email}
              disabled
              className="w-full px-4 py-2.5 rounded-lg border border-slate-300 bg-slate-100 text-slate-600 cursor-not-allowed"
            />
          </div>

          {/* Password */}
          <div className="relative">
            <label className="block text-sm font-medium text-slate-600 mb-1">
              Password
            </label>

            <input
              type={showPassword ? "text" : "password"}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              className="w-full px-4 py-2.5 pr-11 rounded-lg border border-slate-300 focus:ring-2 focus:ring-sky-400 focus:border-sky-400 outline-none"
            />

            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="absolute right-3 top-9 text-slate-500 hover:text-sky-600"
            >
              {showPassword ? <FaEyeSlash /> : <FaEye />}
            </button>
          </div>

          {/* Confirm Password */}
          <div className="relative">
            <label
              className={`block text-sm font-medium mb-1 ${
                isPasswordMismatch ? "text-red-500" : "text-slate-600"
              }`}
            >
              {isPasswordMismatch
                ? "Password does not match"
                : "Confirm Password"}
            </label>

            <input
              type={showConfirmPassword ? "text" : "password"}
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              required
              className={`w-full px-4 py-2.5 pr-11 rounded-lg outline-none border
              ${
                isPasswordMismatch
                  ? "border-red-400 focus:ring-red-300"
                  : "border-slate-300 focus:ring-sky-400 focus:border-sky-400"
              }
              focus:ring-2`}
            />

            <button
              type="button"
              onClick={() => setShowConfirmPassword(!showConfirmPassword)}
              className="absolute right-3 top-9 text-slate-500 hover:text-sky-600"
            >
              {showConfirmPassword ? <FaEyeSlash /> : <FaEye />}
            </button>
          </div>

          {/* Submit */}
          <button
            type="submit"
            className="w-full mt-3 bg-gradient-to-r from-sky-500 to-sky-600 hover:from-sky-600 hover:to-sky-700 text-white py-2.5 rounded-lg font-semibold shadow-md transition"
          >
            Create Account
          </button>
        </form>

        {/* Back */}
        <div className="text-center mt-4">
          <Link
            to="/dashboard/tenants"
            className="text-sm text-sky-600 hover:underline"
          >
            ΓåÉ Back to Tenants List
          </Link>
        </div>
      </div>
    </div>
  );
}

export default CreateAccount;

import React, { useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { CiEdit } from "react-icons/ci";

import { FaEye, FaEyeSlash } from "react-icons/fa";

export default function ViewTenant() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [tenant, setTenant] = useState(() => {
    const list = JSON.parse(localStorage.getItem("tenants")) || [];
    const normalizedList = list.map((t) => ({
      id: t.id || 0,
      name: t.name || "Unknown",
      email: t.email || "Not provided",
      phone: t.phone || "Not provided",
      occupation: t.occupation || t.job || "Not specified",
      dob: t.dob || "Not specified",
      photo: t.photo || "https://via.placeholder.com/150",
      status: t.status || "Pending",
      idFront: t.idFront || "https://via.placeholder.com/300x200",
      idBack: t.idBack || "https://via.placeholder.com/300x200",
    }));

    return normalizedList.find((t) => t.id === Number(id));
  });

  const [showIdModal, setShowIdModal] = useState(false);
  const [showPasswordModal, setShowPasswordModal] = useState(false);
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [loading, setLoading] = useState(false);

  const isMismatch = confirmPassword && newPassword !== confirmPassword;

  const handleUpdatePassword = (e) => {
    e.preventDefault();
    if (isMismatch) return;

    setLoading(true);

    setTimeout(() => {
      const tenants = JSON.parse(localStorage.getItem("tenants")) || [];
      const updated = tenants.map((t) =>
        t.email === tenant.email
          ? { ...t, account: { password: newPassword }, status: "Linked" }
          : t,
      );
      localStorage.setItem("tenants", JSON.stringify(updated));
      setLoading(false);
      setShowPasswordModal(false);
    }, 700);
  };

  if (!tenant) return <p className="p-6 text-gray-500">Tenant not found.</p>;

  return (
    <div className="p-6 bg-sky-50 min-h-screen space-y-6">
      {/* ===== HEADER ===== */}
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-sky-900">Tenant Detail</h2>
        <button
          onClick={() => navigate(-1)}
          className="px-4 py-2 rounded-lg border bg-white hover:bg-sky-100 transition"
        >
          ΓåÉ Back
        </button>
      </div>

      {/* ===== PROFILE CARD ===== */}
      <div className="bg-white rounded-2xl shadow p-6 grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* LEFT */}
        <div className="flex flex-col items-center text-center gap-3">
          <div className="relative">
            <img
              src={tenant.photo}
              alt="Tenant"
              className="w-32 h-32 rounded-full object-cover border-4 border-sky-200"
            />
            <span
              className={`absolute bottom-2 right-2 w-4 h-4 rounded-full border-2 border-white
              ${tenant.status === "Linked" ? "bg-green-500" : "bg-yellow-400"}`}
            ></span>
          </div>

          <h3 className="text-xl font-bold">{tenant.name}</h3>

          <span
            className={`px-4 py-1 rounded-full text-sm font-semibold
            ${
              tenant.status === "Linked"
                ? "bg-green-100 text-green-700"
                : "bg-yellow-100 text-yellow-700"
            }`}
          >
            {tenant.status === "Linked" ? "Account Linked" : "Pending"}
          </span>
        </div>

        {/* RIGHT */}
        <div className="md:col-span-2 space-y-4">
          {/* ACTION BAR */}
          <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
            <h4 className="text-lg font-semibold text-gray-800">
              Tenant Information
            </h4>
            <button
              onClick={() => setShowPasswordModal(true)}
              className="flex items-center gap-1 px-4 py-2 rounded-lg bg-sky-600 text-white hover:bg-sky-700"
            >
              <CiEdit />
              Change Password
            </button>
          </div>

          {/* INFO GRID ΓÇö 3 CARDS FIRST ROW */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            <Info label="Email" value={tenant.email} />
            <Info label="Phone" value={tenant.phone} />
            <Info label="Job / Occupation" value={tenant.occupation} />

            <Info label="Date of Birth" value={tenant.dob} />

            {/* ID CARD */}
            <div
              onClick={() => setShowIdModal(true)}
              className="cursor-pointer p-4 rounded-xl border bg-sky-50 hover:bg-sky-100 transition"
            >
              <p className="text-sm text-gray-500">ID Card</p>
              <p className="font-semibold text-sky-700">View ID Images ΓåÆ</p>
            </div>
          </div>
        </div>
      </div>

      {/* ===== LEASE HISTORY ===== */}
      <div className="bg-white rounded-2xl shadow p-6 space-y-4">
        <div className="flex items-center justify-between">
          <h4 className="text-lg font-semibold">Lease History</h4>
          <button
            onClick={() =>
              navigate(`/dashboard/tenants/createlease`, {
                state: { id: tenant.id, email: tenant.email },
              })
            }
            className="px-4 py-2 rounded-lg bg-green-600 text-white"
          >
            + Create New Lease
          </button>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead className="bg-sky-100">
              <tr>
                <th className="px-4 py-3 text-left">Room</th>
                <th className="px-4 py-3 text-left">Dates</th>
                <th className="px-4 py-3 text-left">Rent</th>
                <th className="px-4 py-3 text-left">Status</th>
              </tr>
            </thead>
            <tbody>
              <tr>
                <td colSpan="4" className="text-center py-10 text-gray-400">
                  No lease history for this tenant.
                </td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>

      {/* ===== ID MODAL ===== */}
        {showIdModal && (
          <div
            className="fixed inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center z-50 px-4"
            onClick={() => setShowIdModal(false)}
          >
            <div
              className="bg-white rounded-2xl shadow-xl max-w-2xl w-full p-6"
              onClick={(e) => e.stopPropagation()}
            >
              <h3 className="text-lg font-bold mb-4 text-center">ID Card</h3>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <img
                  src={tenant.idFront}
                  alt="ID Front"
                  className="rounded-lg border"
                />
                <img
                  src={tenant.idBack}
                  alt="ID Back"
                  className="rounded-lg border"
                />
              </div>

              <div className="text-center mt-6">
                <button
                  onClick={() => setShowIdModal(false)}
                  className="px-5 py-2 rounded-lg border hover:bg-gray-100"
                >
                  Close
                </button>
              </div>
            </div>
          </div>
        )}

        {showPasswordModal && (
          <div
            className="fixed inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center z-50 px-4"
            onClick={() => setShowPasswordModal(false)}
          >
            <div
              className="bg-white rounded-2xl shadow-xl max-w-2xl w-full p-6"
              onClick={(e) => e.stopPropagation()}
            >
              <h2 className="text-2xl font-bold text-sky-900 text-center mb-6">
                Change Tenant Password
              </h2>

              <form
                className="grid grid-cols-1 md:grid-cols-2 gap-6"
                onSubmit={(e) => handleUpdatePassword(e)}
              >
                {/* EMAIL */}
                <div className="flex flex-col">
                  <label className="text-sm font-medium text-slate-600 mb-1">
                    Tenant Email
                  </label>
                  <input
                    type="email"
                    value={tenant.email}
                    disabled
                    className="w-full px-4 py-2.5 rounded-lg border border-slate-300 bg-slate-100 cursor-not-allowed"
                  />
                </div>

                {/* PASSWORDS */}
                <div className="flex flex-col gap-4">
                  {/* New Password */}
                  <div className="relative">
                    <label className="block text-sm font-medium text-slate-600 mb-1">
                      New Password
                    </label>
                    <input
                      type={showNew ? "text" : "password"}
                      value={newPassword}
                      onChange={(e) => setNewPassword(e.target.value)}
                      required
                      className="w-full px-4 py-2.5 pr-11 rounded-lg border border-slate-300 focus:ring-2 focus:ring-sky-400 focus:border-sky-400 outline-none"
                    />
                    <button
                      type="button"
                      onClick={() => setShowNew(!showNew)}
                      className="absolute right-3 top-9 text-slate-500 hover:text-sky-600"
                    >
                      {showNew ? <FaEyeSlash /> : <FaEye />}
                    </button>
                  </div>

                  {/* Confirm Password */}
                  <div className="relative">
                    <label
                      className={`block text-sm font-medium mb-1 ${
                        isMismatch ? "text-red-500" : "text-slate-600"
                      }`}
                    >
                      {isMismatch
                        ? "Passwords do not match"
                        : "Confirm Password"}
                    </label>
                    <input
                      type={showConfirm ? "text" : "password"}
                      value={confirmPassword}
                      onChange={(e) => setConfirmPassword(e.target.value)}
                      required
                      className={`w-full px-4 py-2.5 pr-11 rounded-lg border focus:ring-2 outline-none
                  ${
                    isMismatch
                      ? "border-red-400 focus:ring-red-300"
                      : "border-slate-300 focus:ring-sky-400 focus:border-sky-400"
                  }`}
                    />
                    <button
                      type="button"
                      onClick={() => setShowConfirm(!showConfirm)}
                      className="absolute right-3 top-9 text-slate-500 hover:text-sky-600"
                    >
                      {showConfirm ? <FaEyeSlash /> : <FaEye />}
                    </button>
                  </div>

                  {/* BUTTONS */}
                  <div className="flex gap-4 mt-2">
                    <button
                      type="button"
                      disabled={loading}
                      onClick={() => setShowPasswordModal(false)}
                      className="flex-1 py-2.5 rounded-lg border border-slate-300 hover:bg-slate-100 transition font-medium disabled:opacity-60"
                    >
                      Cancel
                    </button>

                    <button
                      type="submit"
                      disabled={loading || isMismatch}
                      className="flex-1 py-2.5 rounded-lg bg-sky-600 text-white hover:bg-sky-700 transition font-medium disabled:opacity-60"
                    >
                      {loading ? "Updating..." : "Update Password"}
                    </button>
                  </div>
                </div>
              </form>
            </div>
          </div>
        )}
    </div>
  );
}

/* Small reusable info box */
function Info({ label, value }) {
  return (
    <div className="p-4 rounded-xl border bg-white">
      <p className="text-sm text-gray-500">{label}</p>
      <p className="font-semibold text-gray-800">{value}</p>
    </div>
  );
}

import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import toast from "react-hot-toast";

export default function AddBill() {
  const navigate = useNavigate();

  const [leases, setLeases] = useState(() => {
    const saved = JSON.parse(localStorage.getItem("leases")) || [];
    return saved.filter((l) => l.status === "Active");
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!form.leaseId || !form.amount || !form.dueDate) {
      toast.error("Please fill all required fields");
      return;
    }

    if (form.billType === "Other" && !form.otherDesc.trim()) {
      toast.error("Please enter bill description");
      return;
    }

    const description =
      form.billType === "Other" ? form.otherDesc : form.billType;

    const newBill = {
      id: Date.now(),
      date: new Date().toISOString().slice(0, 10),
      dueDate: form.dueDate,
      description,
      amount: Number(form.amount),
      method: "Utility Bill",
      status: form.status,
    };

    const allLeases = JSON.parse(localStorage.getItem("leases")) || [];

    const updated = allLeases.map((l) => {
      if (l.id === Number(form.leaseId)) {
        return {
          ...l,
          bills:
            form.status === "Unpaid"
              ? [...(l.bills || []), newBill]
              : l.bills || [],
          transactions:
            form.status === "Paid"
              ? [...(l.transactions || []), newBill]
              : l.transactions || [],
        };
      }
      return l;
    });

    localStorage.setItem("leases", JSON.stringify(updated));
    toast.success("Bill saved successfully");
    navigate(-1);
  };

  return (
    <div className="min-h-screen bg-sky-50 p-6">
      <div className="max-w-5xl mx-auto bg-white rounded-2xl shadow p-10">
        <h2 className="text-2xl font-bold text-slate-800 mb-8">
          Add Utility Bill
        </h2>

        <form
          onSubmit={handleSubmit}
          className="grid grid-cols-1 md:grid-cols-2 gap-6"
        >
          {/* LEFT COLUMN */}
          <div className="space-y-5">
            {/* SELECT LEASE */}
            <div>
              <label className="block text-sm font-medium mb-1">
                Tenant / Room (Active Lease)
              </label>
              <select
                name="leaseId"
                value={form.leaseId}
                onChange={handleChange}
                className="w-full border rounded-lg px-4 py-2"
              >
                <option value="">-- Select --</option>
                {leases.map((l) => (
                  <option key={l.id} value={l.id}>
                    {l.tenant} - {l.room}
                  </option>
                ))}
              </select>
            </div>

            {/* BILL TYPE */}
            <div>
              <label className="block text-sm font-medium mb-1">
                Bill Type
              </label>
              <select
                name="billType"
                value={form.billType}
                onChange={handleChange}
                className="w-full border rounded-lg px-4 py-2"
              >
                <option value="Water">Water</option>
                <option value="Electricity">Electricity</option>
                <option value="Other">Other</option>
              </select>
            </div>

            {/* OTHER DESC */}
            {form.billType === "Other" && (
              <div>
                <label className="block text-sm font-medium mb-1">
                  Description
                </label>
                <input
                  type="text"
                  name="otherDesc"
                  value={form.otherDesc}
                  onChange={handleChange}
                  placeholder="Enter description..."
                  className="w-full border rounded-lg px-4 py-2"
                />
              </div>
            )}
          </div>

          {/* RIGHT COLUMN */}
          <div className="space-y-5">
            {/* AMOUNT */}
            <div>
              <label className="block text-sm font-medium mb-1">
                Amount ($)
              </label>
              <input
                type="number"
                name="amount"
                value={form.amount}
                onChange={handleChange}
                className="w-full border rounded-lg px-4 py-2"
              />
            </div>

            {/* DUE DATE */}
            <div>
              <label className="block text-sm font-medium mb-1">Due Date</label>
              <input
                type="date"
                name="dueDate"
                value={form.dueDate}
                onChange={handleChange}
                className="w-full border rounded-lg px-4 py-2"
              />
            </div>

            {/* STATUS */}
            <div>
              <label className="block text-sm font-medium mb-1">Status</label>
              <select
                name="status"
                value={form.status}
                onChange={handleChange}
                className="w-full border rounded-lg px-4 py-2"
              >
                <option value="Unpaid">Unpaid</option>
                <option value="Paid">Paid</option>
              </select>
            </div>
          </div>

          {/* BUTTON ROW */}
          <div className="md:col-span-2 flex justify-end gap-4 pt-6 border-t mt-4">
            <button
              type="button"
              onClick={() => navigate(-1)}
              className="px-6 py-2 rounded-lg border hover:bg-slate-100"
            >
              Cancel
            </button>

            <button
              type="submit"
              className="px-8 py-2 rounded-lg bg-green-600 text-white hover:bg-green-700 shadow"
            >
              Save Bill
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
